from flask import Flask, request, jsonify, redirect, render_template_string
import json
import os
import re
import time
import uuid

app = Flask(__name__)

LOG_FILE = os.environ.get("SIM_LOG_FILE", "simulation_events.jsonl")

PID_RE = re.compile(r"^[A-Za-z0-9_-]{1,64}$")

ALLOWED_EVENT_TYPES = {
    "email_open",
    "email_link_click",
    "landing_visit",
    "focus_username",
    "focus_password",
    "submit_attempt",
    "debrief_view",
}

ALLOWED_META_KEYS = {
    "seconds_on_page",
    "username_filled",
    "password_filled",
}


def safe_pid(raw_pid: str | None) -> str:
    """
    참가자 식별자 정규화.
    실험에서 참가자별 구분이 필요 없다면 random pid를 사용하면 됩니다.
    """
    if raw_pid and PID_RE.match(raw_pid):
        return raw_pid
    return "anon-" + uuid.uuid4().hex[:12]


def append_event(record: dict) -> None:
    with open(LOG_FILE, "a", encoding="utf-8") as f:
        f.write(json.dumps(record, ensure_ascii=False) + "\n")


def log_event(event_type: str, pid: str, page: str, meta: dict | None = None) -> None:
    if event_type not in ALLOWED_EVENT_TYPES:
        return

    clean_meta = {}
    if isinstance(meta, dict):
        for key, value in meta.items():
            if key not in ALLOWED_META_KEYS:
                continue

            if key in {"username_filled", "password_filled"}:
                clean_meta[key] = bool(value)
            elif key == "seconds_on_page":
                try:
                    clean_meta[key] = max(0, min(float(value), 3600.0))
                except Exception:
                    pass

    record = {
        "server_ts": time.time(),
        "event_type": event_type,
        "pid": pid,
        "page": page,
        "meta": clean_meta,
        "remote_addr": request.remote_addr,
        "user_agent": request.headers.get("User-Agent", "")[:300],
    }
    append_event(record)


